SELECT id, applicant_id AS applicantId, applicant_name AS applicantName, animal_id AS animalId, animal_name AS animalName, aid_type AS aidType, aid_amount AS aidAmount, reason, status, audit_time AS auditTime, auditor_id AS auditorId, auditor_name AS auditorName, is_deleted AS isDeleted, create_time AS createTime, update_time AS updateTime FROM aid_application
is_deleted = 0
AND applicant_id = #{applicantId}
AND applicant_name LIKE concat('%', #{applicantName}, '%')
AND animal_id = #{animalId}
AND animal_name LIKE concat('%', #{animalName}, '%')
AND aid_type = #{aidType}
AND status = #{status}
ORDER BY create_time DESC
LIMIT #{current}, #{size}

